import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define optimized CUDA kernel for fused KL divergence with built-in numerical safeguards
kl_div_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cooperative_groups.h>
#include <cooperative_groups/reduce.h>
#include <cfloat>

namespace cg = cooperative_groups;

template<typename scalar_t>
__device__ __forceinline__ scalar_t safe_log(scalar_t x, scalar_t eps) {
    // Ensure log arguments are positive and above numerical precision threshold
    return log(fmaxf(x, eps));
}

template<typename scalar_t>
__global__ void fused_kl_div_kernel(
    const scalar_t* __restrict__ predictions,
    const scalar_t* __restrict__ targets,
    scalar_t* __restrict__ output,
    int batch_size,
    int seq_len,
    scalar_t epsilon  // Explicit epsilon parameter for numerical stability
) {
    // Each block processes one batch element
    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    const scalar_t* pred_batch = predictions + batch_idx * seq_len;
    const scalar_t* target_batch = targets + batch_idx * seq_len;

    // Thread block and warp setup
    cg::thread_block block = cg::this_thread_block();
    cg::thread_block_tile<32> warp = cg::tiled_partition<32>(block);

    scalar_t thread_sum = 0.0f;
    scalar_t thread_valid = 0.0f;  // Track if computation was valid

    // Process elements with stride equal to total threads in block
    int tid = threadIdx.x;
    int total_threads = blockDim.x;

    for (int idx = tid; idx < seq_len; idx += total_threads) {
        scalar_t p = pred_batch[idx];
        scalar_t t = target_batch[idx];

        // Validate inputs at kernel level with explicit epsilon
        if (p <= 0.0f || t <= 0.0f) {
            // Invalid probability detected - kernel will handle this
            thread_valid = -1.0f;  // Mark as invalid
            continue;
        }

        // KL divergence with safe logarithmic operations
        thread_sum += t * (safe_log(t, epsilon) - safe_log(p, epsilon));
        thread_valid = 1.0f;  // Mark as valid
    }

    // Warp reduction for sum
    scalar_t warp_sum = cg::reduce(warp, thread_sum, cg::plus<scalar_t>());
    scalar_t warp_valid = cg::reduce(warp, thread_valid, cg::max<scalar_t>());

    // Shared memory for warp results
    __shared__ struct { scalar_t sum; scalar_t valid; } block_results[32];
    if (warp.thread_rank() == 0) {
        block_results[warp.meta_group_rank()].sum = warp_sum;
        block_results[warp.meta_group_rank()].valid = warp_valid;
    }
    block.sync();

    // First warp reduces all warp sums and checks validity
    if (warp.meta_group_rank() == 0) {
        scalar_t block_sum = 0.0f;
        scalar_t block_valid = 0.0f;
        int num_warps = (total_threads + 31) / 32;

        for (int i = warp.thread_rank(); i < num_warps; i += warp.size()) {
            block_sum += block_results[i].sum;
            block_valid = fmaxf(block_valid, block_results[i].valid);
        }

        scalar_t final_sum = cg::reduce(warp, block_sum, cg::plus<scalar_t>());
        scalar_t final_valid = cg::reduce(warp, block_valid, cg::max<scalar_t>());

        if (warp.thread_rank() == 0) {
            // Output NaN if any thread detected invalid probabilities
            output[batch_idx] = (final_valid >= 0.0f) ? final_sum : 
                                static_cast<scalar_t>(NAN);
        }
    }
}

torch::Tensor fused_kl_div_cuda(torch::Tensor predictions, torch::Tensor targets) {
    // Ensure inputs are on GPU and contiguous
    predictions = predictions.contiguous();
    targets = targets.contiguous();

    auto batch_size = predictions.size(0);
    auto seq_len = predictions.size(1);

    // Create output tensor for per-batch results
    auto output = torch::zeros({batch_size}, predictions.options());

    // Define epsilon INSIDE the kernel call - not dependent on external Python constants
    constexpr float EPSILON = 1e-12f;

    // Optimized kernel launch configuration
    int threads = 256;
    int blocks = batch_size;

    AT_DISPATCH_FLOATING_TYPES(predictions.scalar_type(), "fused_kl_div_kernel", ([&] {
        fused_kl_div_kernel<scalar_t><<<blocks, threads>>>(
            predictions.data_ptr<scalar_t>(),
            targets.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            batch_size,
            seq_len,
            static_cast<scalar_t>(EPSILON)  // Pass epsilon explicitly
        );
    }));

    // Check for invalid computations (NaNs)
    if (torch::isnan(output).any().item<bool>()) {
        // Fall back to PyTorch's reference implementation if kernel detects issues
        return torch::kl_div(predictions.log(), targets, reduction='batchmean', log_target=False);
    }

    // Return batchmean reduction
    return output.mean();
}
